SELECT COUNT(1)
FROM sys_user
WHERE is_deleted = FALSE

    AND (
        username LIKE CONCAT('%', #{keywords}, '%')
        OR real_name LIKE CONCAT('%', #{keywords}, '%')
        OR mobile LIKE CONCAT('%', #{keywords}, '%')
    )


    AND status = #{status}


    AND unit_id = #{unitId}

SELECT u.id, u.unit_id, su.unit_name, u.username, u.real_name, u.job_title, u.mobile, u.status, parent_user_id, level_no, create_time, update_time FROM sys_user u LEFT JOIN sys_org_unit su ON su.id = u.unit_id WHERE u.is_deleted = FALSE
AND ( u.username LIKE CONCAT('%', #{keywords}, '%') OR u.real_name LIKE CONCAT('%', #{keywords}, '%') OR u.mobile LIKE CONCAT('%', #{keywords}, '%') )
AND u.status = #{status}
AND u.unit_id = #{unitId}
ORDER BY u.update_time DESC, u.id DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(1)
FROM sys_user
WHERE is_deleted = FALSE
  AND id = #{userId}

    AND (
        username LIKE CONCAT('%', #{request.keywords}, '%')
        OR real_name LIKE CONCAT('%', #{request.keywords}, '%')
        OR mobile LIKE CONCAT('%', #{request.keywords}, '%')
    )


    AND status = #{request.status}

SELECT u.id, u.unit_id, su.unit_name, u.username, u.real_name, u.job_title, u.mobile, u.status, parent_user_id, level_no, create_time, update_time FROM sys_user u LEFT JOIN sys_org_unit su ON su.id = u.unit_id WHERE u.is_deleted = FALSE AND u.id = #{userId}
AND ( u.username LIKE CONCAT('%', #{request.keywords}, '%') OR u.real_name LIKE CONCAT('%', #{request.keywords}, '%') OR u.mobile LIKE CONCAT('%', #{request.keywords}, '%') )
AND u.status = #{request.status}
ORDER BY u.update_time DESC, u.id DESC LIMIT #{request.pageSize} OFFSET #{request.offset}

